import React, { useEffect, useState } from 'react';
import ProductTable from './components/ProductTable';
import SettingsPage from './components/SettingsPage';

const sidebarItems = [
  { label: 'Dashboard', path: '/' },
  { label: 'Assets', path: '/assets' },
];

const normalizePath = (path: string) => {
  const cleaned = path.replace(/\\/g, '/').replace(/\/$/, '');
  if (cleaned === '' || cleaned === '/') return '/';
  if (cleaned === '/dashboard') return '/';
  return cleaned;
};

function App() {
  const [activeTab, setActiveTab] = useState<number>(0);
  const tabs = [
    'Product Type',
    'Product',
    'Vendor',
    'Software Type',
    'Software Category',
    'Software License Type',
    'Asset State',
    'Manufacturer',
  ];

  const renderTabContent = () => {
    switch (activeTab) {
      case 0:
        return <ProductTypeTable />;
      case 1:
        return <ProductTable />;
     
      default:
        return (
          <div className="bg-white rounded-lg shadow-sm p-6 text-gray-700">
            <h2 className="text-lg font-semibold mb-2">{tabs[activeTab]}</h2>
            <p className="text-sm text-gray-500">This section is not implemented yet.</p>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen bg-[#f5f6f8] text-slate-900">
      <div className="fixed inset-y-0 left-0 w-72 border-r border-slate-700/40 bg-[#1f2a44] text-slate-100 shadow-xl">
        <div className="flex h-full flex-col">
          <div className="px-6 py-6 border-b border-slate-700/50">
            <div className="text-lg font-semibold tracking-wide">Asset Customisation</div>
            <p className="mt-2 text-sm text-slate-400">Enterprise asset dashboard</p>
          </div>
          <nav className="flex-1 space-y-1 px-3 py-5">
            {sidebarItems.map((item, index) => (
              <button
                key={item.label}
                onClick={() => setActiveTab(index)}
                className={`flex w-full items-center gap-3 rounded-2xl px-4 py-3 text-left text-sm font-medium transition ${
                  activeTab === index
                    ? 'bg-slate-100/10 text-white shadow-inner'
                    : 'text-slate-300 hover:bg-slate-100/10 hover:text-white'
                }`}
              >
                <span className="inline-flex h-9 w-9 items-center justify-center rounded-2xl bg-slate-700/80 text-slate-200">
                  {item.label.charAt(0)}
                </span>
                <span>{item.label}</span>
              </button>
            ))}
          </nav>
          <div className="border-t border-slate-700/50 px-6 py-5">
            <div className="rounded-2xl bg-slate-800 p-4 text-sm text-slate-300">
              <div className="font-semibold text-white">Admin User</div>
              <p className="mt-1 text-slate-400">kuldip@example.com</p>
            </div>
          </div>
        </div>
      </div>

      <div className="ml-72 min-h-screen">
        <header className="sticky top-0 z-30 border-b border-slate-200/80 bg-white/95 backdrop-blur-md px-6 py-4 shadow-sm">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div className="flex flex-1 items-center gap-3">
              <div className="relative w-full max-w-md">
                <span className="pointer-events-none absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">🔍</span>
                <input
                  type="text"
                  placeholder="Search settings, assets..."
                  className="w-full rounded-2xl border border-slate-200 bg-slate-50 py-3 pl-11 pr-4 text-sm text-slate-900 shadow-sm focus:border-slate-400 focus:outline-none focus:ring-2 focus:ring-slate-200"
                />
              </div>
            </div>
            <div className="flex items-center gap-3">
              <button className="rounded-full border border-slate-200 bg-white p-3 text-slate-600 shadow-sm hover:bg-slate-50">
                ☀️
              </button>
              <button className="rounded-full border border-slate-200 bg-white p-3 text-slate-600 shadow-sm hover:bg-slate-50">
                ⚙️
              </button>
              <button className="rounded-full border border-slate-200 bg-white p-3 text-slate-600 shadow-sm hover:bg-slate-50">
                🔔
              </button>
              <div className="flex items-center gap-3 rounded-2xl border border-slate-200 bg-white px-3 py-2 shadow-sm">
                <div className="h-9 w-9 rounded-full bg-blue-600 text-sm font-semibold text-white flex items-center justify-center">K</div>
                <div>
                  <div className="text-sm font-medium text-slate-900">Kuldip</div>
                  <div className="text-xs text-slate-500">Admin</div>
                </div>
              </div>
            </div>
          </div>
        </header>

        <main className="px-6 py-6">
          <div className="mb-6 flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
            <div>
              <div className="text-sm uppercase tracking-[0.24em] text-slate-500">Customisation</div>
              <h1 className="mt-2 text-3xl font-semibold text-slate-900">Customisation - Asset - {sidebarItems[activeTab].label}</h1>
            </div>
            <div className="text-sm text-slate-500">
              <span>Home</span>
              <span className="mx-2">›</span>
              <span>Customisation</span>
              <span className="mx-2">›</span>
              <span>Asset</span>
              <span className="mx-2">›</span>
              <span className="text-slate-900 font-medium">{sidebarItems[activeTab].label}</span>
            </div>
          </div>

          <div className="rounded-[24px] border border-slate-200 bg-white p-5 shadow-sm">
            <div className="flex flex-wrap gap-4 border-b border-slate-200/90 pb-4">
              {sidebarItems.map((item, index) => (
                <button
                  key={item.label}
                  onClick={() => setActiveTab(index)}
                  className={`inline-flex items-center gap-2 border-b-2 pb-3 text-sm font-medium transition ${
                    activeTab === index
                      ? 'border-slate-900 text-slate-900'
                      : 'border-transparent text-slate-500 hover:text-slate-700'
                  }`}
                >
                  {item.label}
                </button>
              ))}
            </div>

            <div className="mt-6">{renderTabContent()}</div>
          </div>
        </main>
      </div>
    </div>
  );
}

export default App;
